import{_ as r,a}from"./chunks/dgrid-openclaw-demo.Rr2R33J3.js";import{_ as t,c as o,o as i,ag as n}from"./chunks/framework.S-Qvb3wi.js";const b=JSON.parse('{"title":"AI 게이트웨이 통합 튜토리얼","description":"","frontmatter":{},"headers":[],"relativePath":"kr/AI-Gateway-Integrations.md","filePath":"kr/AI-Gateway-Integrations.md"}'),s={name:"kr/AI-Gateway-Integrations.md"};function l(d,e,p,g,h,I){return i(),o("div",null,e[0]||(e[0]=[n('<h1 id="ai-게이트웨이-통합-튜토리얼" tabindex="-1">AI 게이트웨이 통합 튜토리얼 <a class="header-anchor" href="#ai-게이트웨이-통합-튜토리얼" aria-label="Permalink to &quot;AI 게이트웨이 통합 튜토리얼&quot;">​</a></h1><p>이 페이지는 <strong>DGrid AI 게이트웨이</strong>를 다양한 개발 도구/SDK에 연결하는 실전 튜토리얼을 한 곳에 모아 둔 목록입니다.</p><h2 id="cursor-openai-base-url-재정의" tabindex="-1">Cursor (OpenAI Base URL 재정의) <a class="header-anchor" href="#cursor-openai-base-url-재정의" aria-label="Permalink to &quot;Cursor (OpenAI Base URL 재정의)&quot;">​</a></h2><ol><li><code>DGRID_API_KEY</code>를 준비합니다 (선행 조건은 <a href="/kr/AI-Gateway">AI 게이트웨이</a> 참고).</li><li><strong>Cursor Settings</strong> → <strong>Models</strong>로 이동합니다.</li><li><strong>API Keys</strong>에서 <strong>Override OpenAI Base URL</strong>을 활성화합니다.</li><li>Base URL을 아래처럼 설정합니다: <ul><li><code>https://api.dgrid.ai/v1</code></li></ul></li><li><strong>OpenAI API Key</strong>에 <code>DGRID_API_KEY</code>를 입력합니다.</li><li>모델 이름은 DGrid 형식으로 사용합니다 (예: <code>openai/gpt-4o</code>).</li></ol><p><img src="'+r+'" alt="Cursor settings example"></p><p>전체 가이드(블로그): <a href="https://blog.dgrid.ai/posts/2026-02-18/" target="_blank" rel="noreferrer">How to Configure and Use DGrid AI Gateway in Cursor</a></p><h2 id="openai-sdk-node-js-python" tabindex="-1">OpenAI SDK (Node.js / Python) <a class="header-anchor" href="#openai-sdk-node-js-python" aria-label="Permalink to &quot;OpenAI SDK (Node.js / Python)&quot;">​</a></h2><ul><li>참고: <a href="/kr/AI-Gateway#빠른-시작">AI 게이트웨이 빠른 시작</a></li></ul><h2 id="openclaw" tabindex="-1">OpenClaw <a class="header-anchor" href="#openclaw" aria-label="Permalink to &quot;OpenClaw&quot;">​</a></h2><p>OpenClaw에서도 <strong>DGrid AI 게이트웨이</strong>의 OpenAI 호환 엔드포인트를 사용해 쉽게 연결할 수 있습니다.</p><ol><li>OpenClaw의 모델 또는 provider 설정 화면을 엽니다.</li><li>API Base URL을 <code>https://api.dgrid.ai/v1</code>로 설정합니다.</li><li>API Key 항목에 <code>DGRID_API_KEY</code>를 입력합니다.</li><li>DGrid에서 지원하는 모델 ID를 선택합니다.</li><li>설정을 저장한 뒤 테스트 요청으로 정상 동작을 확인합니다.</li></ol><video controls preload="metadata" style="width:100%;border-radius:12px;margin-top:12px;"><source src="'+a+'" type="video/mp4"> Your browser does not support the video tag. </video><h2 id="블로그-통합-튜토리얼-모음" tabindex="-1">블로그 통합 튜토리얼 모음 <a class="header-anchor" href="#블로그-통합-튜토리얼-모음" aria-label="Permalink to &quot;블로그 통합 튜토리얼 모음&quot;">​</a></h2><ul><li><strong>AI as Workspace (AIaW)</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-10/" target="_blank" rel="noreferrer">Step-by-Step Guide: Configure DGrid AI Gateway in AI as Workspace (AIaW)</a></li><li><strong>AnythingLLM</strong>: <a href="https://blog.dgrid.ai/posts/2026-01-30/" target="_blank" rel="noreferrer">Tutorial: Using DGrid AI Gateway with AnythingLLM</a></li><li><strong>Chatbox</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-09/" target="_blank" rel="noreferrer">Step-by-Step Guide: Configure DGrid AI Gateway in Chatbox</a></li><li><strong>Claude Code</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-12/" target="_blank" rel="noreferrer">Use Claude Code with DGrid</a></li><li><strong>Codex CLI</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-23/" target="_blank" rel="noreferrer">Using Codex CLI with DGrid: A Complete Guide</a></li><li><strong>LibreChat</strong>: <a href="https://blog.dgrid.ai/posts/2026-01-28/" target="_blank" rel="noreferrer">Using DGrid with LibreChat: A Step-by-Step Guide</a></li><li><strong>LobeChat</strong>: <a href="https://blog.dgrid.ai/posts/2026-02-09/" target="_blank" rel="noreferrer">Configuring and Utilizing DGrid AI Gateway in LobeChat: A Full Guide</a></li><li><strong>Open WebUI</strong>: <a href="https://blog.dgrid.ai/posts/2026-01-22_2/" target="_blank" rel="noreferrer">Using DGrid AI Gateway with Open WebUI: A Comprehensive Guide</a></li><li><strong>OpenClaw (에이전트 플랫폼)</strong>: <a href="https://blog.dgrid.ai/posts/2026-02-02/" target="_blank" rel="noreferrer">Supercharging OpenClaw with DGrid: The Ultimate AI Agent Setup</a></li><li><strong>OpenClaw (노코드)</strong>: <a href="https://blog.dgrid.ai/posts/2026-02-27/" target="_blank" rel="noreferrer">Step-by-Step Guide: OpenClaw Installation &amp; DGrid AI Gateway Setup (No Code Required)</a></li><li><strong>Vercel AI SDK</strong>: <a href="https://blog.dgrid.ai/posts/2026-03-26/" target="_blank" rel="noreferrer">How to Use DGrid AI Gateway with the Vercel AI SDK</a></li></ul>',14)]))}const c=t(s,[["render",l]]);export{b as __pageData,c as default};
